import { useEffect, useState } from "react";
import API from "../../api/axios";
import {
  Button,
  TextField,
  Typography,
  Box,
  Card,
  CardContent,
} from "@mui/material";
import { useNavigate } from "react-router-dom";

export default function Projects() {
  const navigate = useNavigate();

  const [projects, setProjects] = useState([]);

  const [projectForm, setProjectForm] = useState({
    name: "",
    description: "",
    start_date: "",
    end_date: "",
  });

  // 🔥 FETCH PROJECTS
  const fetchProjects = async () => {
    try {
      const res = await API.get("projects/");
      setProjects(res.data);
    } catch (err) {
      console.log("ERROR:", err);
    }
  };

  useEffect(() => {
    fetchProjects();
  }, []);

  // 🔥 CREATE PROJECT
  const createProject = async () => {
    try {
      await API.post("projects/create/", projectForm);
      alert("Project Created ✅");
      fetchProjects();
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <Box
      sx={{
        height: "100vh",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        background: "#f4f6f8",
      }}
    >
      <Card
        sx={{
          width: { xs: "90%", sm: 420 },
          p: 3,
          borderRadius: 4,
          background: "linear-gradient(135deg, #1e3c72, #2a5298)",
          color: "#fff",
          boxShadow: "0 10px 30px rgba(0,0,0,0.3)",
        }}
      >
        <CardContent>
          <Typography variant="h6" textAlign="center" mb={2}>
            🚀 Create Project
          </Typography>

          <TextField
            fullWidth
            label="Project Name"
            margin="normal"
            InputLabelProps={{ style: { color: "#fff" } }}
            sx={{ input: { color: "#fff" } }}
            onChange={(e) =>
              setProjectForm({ ...projectForm, name: e.target.value })
            }
          />

          <TextField
            fullWidth
            label="Description"
            margin="normal"
            InputLabelProps={{ style: { color: "#fff" } }}
            sx={{ input: { color: "#fff" } }}
            onChange={(e) =>
              setProjectForm({
                ...projectForm,
                description: e.target.value,
              })
            }
          />

          <TextField
            fullWidth
            type="date"
            margin="normal"
            InputLabelProps={{ shrink: true }}
            onChange={(e) =>
              setProjectForm({
                ...projectForm,
                start_date: e.target.value,
              })
            }
          />

          <TextField
            fullWidth
            type="date"
            margin="normal"
            InputLabelProps={{ shrink: true }}
            onChange={(e) =>
              setProjectForm({
                ...projectForm,
                end_date: e.target.value,
              })
            }
          />

          <Button
            fullWidth
            variant="contained"
            sx={{ mt: 2 }}
            onClick={createProject}
          >
            CREATE PROJECT
          </Button>

          {/* 🔥 VIEW BUTTON */}
          <Button
            fullWidth
            variant="outlined"
            sx={{ mt: 2, color: "#fff", borderColor: "#fff" }}
            onClick={() => navigate("/admin/projects/list")}
          >
            VIEW PROJECT LIST
          </Button>
        </CardContent>
      </Card>
    </Box>
  );
}
